import{_ as e,o,c as t,a3 as n}from"./chunks/framework.CH_GxKL1.js";const c=JSON.parse('{"title":"Doing the Work (and Overcoming Procrastination)","description":"","frontmatter":{"indexDrivenFooter":{"parent":{"text":"Dopamine Detox","link":"/readings/Dopamine_Detox/"},"prev":{"text":"ch04 - How to Do a Dopamine Detox","link":"/readings/Dopamine_Detox/contexts/4_A_Three-Step_Method_for_a_Successful_Detox"},"next":{"text":"ch06 Avoiding Dopamine Relapse","link":"/readings/Dopamine_Detox/contexts/6_Avoiding_Dopamine_Relapse"}},"prev":{"text":"ch04 - How to Do a Dopamine Detox","link":"/readings/Dopamine_Detox/contexts/4_A_Three-Step_Method_for_a_Successful_Detox"},"next":{"text":"ch06 Avoiding Dopamine Relapse","link":"/readings/Dopamine_Detox/contexts/6_Avoiding_Dopamine_Relapse"}},"headers":[],"relativePath":"readings/Dopamine_Detox/contexts/5_Doing_the_Work_and_Overcoming_Procrastination.md","filePath":"readings/Dopamine_Detox/contexts/5_Doing_the_Work_and_Overcoming_Procrastination.md","lastUpdated":1782825062000}'),i={name:"readings/Dopamine_Detox/contexts/5_Doing_the_Work_and_Overcoming_Procrastination.md"};function r(p,a,l,h,s,_){return o(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="doing-the-work-and-overcoming-procrastination" tabindex="-1">Doing the Work (and Overcoming Procrastination) <a class="header-anchor" href="#doing-the-work-and-overcoming-procrastination" aria-label="Permalink to &quot;Doing the Work (and Overcoming Procrastination)&quot;">​</a></h1><p>多巴胺排毒的主要目标之一是降低你的刺激水平，以帮助你更有动力去完成关键任务。在这一部分，我们将看看你可以做些什么来保持势头并克服拖延倾向。</p><h2 id="规划你的一天" tabindex="-1">规划你的一天 <a class="header-anchor" href="#规划你的一天" aria-label="Permalink to &quot;规划你的一天&quot;">​</a></h2><p>有意图地安排每一天，是提高生产力的有效方法。当你每天花时间决定想要完成什么时，你就限制了分心的风险。因此，你越是有意识地安排，效果就越好。</p><p>规划你的一天很重要，原因如下：</p><ul><li>它给你一个机会来明确哪些任务是重要的，哪些不是。</li><li>它减少你的大脑在一天中干扰你的几率。因为你确切地知道自己必须做什么，你可以顺利地从一个任务过渡到下一个，没有干扰。</li><li>你会感到压力更小，更有掌控感。不是对你的环境做出反应并让它干扰你，而是主动地朝着你的目标前进。</li></ul><h3 id="如何规划你的一天" tabindex="-1">如何规划你的一天 <a class="header-anchor" href="#如何规划你的一天" aria-label="Permalink to &quot;如何规划你的一天&quot;">​</a></h3><p>你不需要花哨的工具来规划你的一天。相反，你可以使用一种被许多人遗忘的秘密技术——笔和纸。简单地写下你今天必须完成的几项关键任务。三到五项任务可能是理想的。按重要性排列它们，然后开始做你的第一项任务。一旦完成，继续下一项。重复这个过程，直到你完成列表中的所有任务。</p><p>现在，这里有几点需要考虑：</p><p>确保这些是推动进展的关键任务。为了帮助你识别主要任务，你可以问自己以下问题：</p><p>如果我今天只能完成一项任务，哪一项会产生最大的影响？</p><p>如果你仍然不确定，问自己这个问题：</p><p>如果我在休假一个月之前只能完成一项任务，那项任务会是什么？</p><p>你会注意到，你最重要的任务往往是你最不想做的那些。也许是因为它们具有挑战性。也许你不知道从哪里开始。或者，也许它们很无聊。但你的多巴胺排毒将有助于让这些任务更容易处理。</p><p>请注意，你可以使用同样的方法来设定每周、每季度、每月和每年的目标。我还建议你创建一个长期愿景。它可以是一个五年或十年计划。当然，它不会是完美的，但仅仅有一个前进方向的大致想法就会产生巨大的差异。</p><p>要设定短期目标，反推你必须做什么才能达到长期目标。例如，如果我想在接下来的九十天内写一本书，一个目标可以是创建大纲。另一个目标可以是完成初稿。而为了达到那个目标，我可以设定一个具体的每日字数。</p><hr><h3 id="行动步骤" tabindex="-1">行动步骤 <a class="header-anchor" href="#行动步骤" aria-label="Permalink to &quot;行动步骤&quot;">​</a></h3><p>使用你的行动指南或单独的一张纸，写下你的每日和每周目标。</p><h2 id="每天早上安排一项主要任务来执行" tabindex="-1">每天早上安排一项主要任务来执行 <a class="header-anchor" href="#每天早上安排一项主要任务来执行" aria-label="Permalink to &quot;每天早上安排一项主要任务来执行&quot;">​</a></h2><p>尽管关于生产力的书籍成千上万，但只有少数几个原则真正重要。我相信最重要的一个是识别你的关键任务，并在早晨第一件事就处理它——并坚持这样做。</p><p>即使你可能有永无止境的待办事项清单，但总有一些主要任务，一旦完成，就会大幅提升你的生产力。除非你能完成它们，否则其他一切都不那么重要。</p><p>生产力的关键可以用三个词来概括：</p><p><strong>1. 专注</strong>（Focus）是你保持注意力、在工作时避免分心或拖延的能力。</p><p><strong>2. 坚持</strong>（Consistency）意味着养成每天、周复一周、月复一月、年复一年地完成关键任务的习惯。</p><p><strong>3. 影响力</strong>（Impact）意味着识别你的关键任务（那些对你长期成功有最大影响的任务）并尽可能频繁地处理它们。</p><p>生产力因此可以被定义为：<strong>持续地专注于你最具影响力的任务</strong>。</p><p>现在，让我们看看你可以具体做些什么来每天保持专注于最重要的任务。</p><h2 id="培养极致专注力" tabindex="-1">培养极致专注力 <a class="header-anchor" href="#培养极致专注力" aria-label="Permalink to &quot;培养极致专注力&quot;">​</a></h2><p>培养极致专注力是你可以做的提高生产力最重要的事情之一。每天仅仅专注于你的关键任务四十五分钟，你取得的进步就可以超过你几乎做任何其他事情。</p><p>在这一部分，我们将讨论你可以做的具体事情来培养专注力并每天完成关键任务。</p><h3 id="_1-每天同一时间待在同一地点" tabindex="-1">1. 每天同一时间待在同一地点 <a class="header-anchor" href="#_1-每天同一时间待在同一地点" aria-label="Permalink to &quot;1. 每天同一时间待在同一地点&quot;">​</a></h3><p>正如我们之前提到的，一个简单的每日例行程序将帮助你训练大脑，帮助你感到更有掌控感，并降低你的刺激水平。结果就是，开始工作会变得更容易。</p><p>能加强你例行程序的一件事，是每天同一时间待在同一地点。著名作家斯蒂芬·金每天同一时间坐在他的书桌前写作。他不等待灵感来临。相反，他开始写，知道灵感会随着他沉浸在工作中而到来。做同样的事。选择一个时间和地点，每天在那里处理你的主要任务。然后，一天一天地练习做这件事，你将逐渐培养你的坚持和专注。</p><p>记住，生产力不过就是专注于你最具影响力的任务并坚持这样做。</p><p>你呢？你将在哪里投入时间去完成最重要的工作，以及你将何时开始？</p><h3 id="_2-选择一个触发器" tabindex="-1">2. 选择一个触发器 <a class="header-anchor" href="#_2-选择一个触发器" aria-label="Permalink to &quot;2. 选择一个触发器&quot;">​</a></h3><p>在创建你的例行程序时，选择一个特定的触发器。它可以是泡茶并坐在桌前。也可以是完成你的冥想环节。尝试选择一个有助于平静你思绪的触发器。当你放松时，你会觉得更容易开始工作。</p><p>你呢？什么活动可以启动你的每日例行程序？</p><h3 id="_3-开始行动" tabindex="-1">3. 开始行动 <a class="header-anchor" href="#_3-开始行动" aria-label="Permalink to &quot;3. 开始行动&quot;">​</a></h3><p>一旦你创建了例行程序并确定了触发器，就开始行动。如果你能开始工作几分钟，你很可能会积累足够的势头继续下去。你甚至可能体验到心流。（由心理学家 Mihaly Csíkszentmihályi 命名，&quot;心流&quot;是一种心理状态，在这种状态中，你完全沉浸在一项活动中，变得高度专注，同时体验到一种潜在的愉悦感）。再次强调，你越是放松，就越容易专注。所以，只管开始，不要担心要完美地完成任务。如果你感觉不到动力或创造力也没关系，采取行动<strong>会</strong>产生动力并激发你的创造力。</p><h3 id="_4-消除干扰" tabindex="-1">4. 消除干扰 <a class="header-anchor" href="#_4-消除干扰" aria-label="Permalink to &quot;4. 消除干扰&quot;">​</a></h3><p>当你工作时，移除所有干扰。关闭手机通知，断开社交媒体，远离互联网，除非是用于特定研究。此外，请他人不要打扰你。你越是练习无干扰地工作，你的专注力就会变得越强。</p><h3 id="_5-不间断地工作" tabindex="-1">5. 不间断地工作 <a class="header-anchor" href="#_5-不间断地工作" aria-label="Permalink to &quot;5. 不间断地工作&quot;">​</a></h3><p>现在你已经消除了干扰，持续不间断地工作。我建议最多进行四十五分钟的高强度工作。如果你想做几个时段，在每个工作块之间休息五到十分钟。</p><p>遵循以上五个步骤将增强你的专注力并提高你的生产力。而且，随着你拖延得越少，你会感觉更好，这将对生活的其他领域产生积极影响。</p><p>要了解更多关于如何培养极致专注力，请参考本系列的第三本书，《<em>强大专注力</em>》。</p><hr><h3 id="行动步骤-1" tabindex="-1">行动步骤 <a class="header-anchor" href="#行动步骤-1" aria-label="Permalink to &quot;行动步骤&quot;">​</a></h3><p>使用你的行动指南，按照以下步骤培养极致专注力。</p><h2 id="警惕开放系统" tabindex="-1">警惕开放系统 <a class="header-anchor" href="#警惕开放系统" aria-label="Permalink to &quot;警惕开放系统&quot;">​</a></h2><p>具有最大干扰潜力的活动通常属于一个开放系统。</p><p>什么是开放系统？</p><p>开放系统简单来说就是一个为你提供持续且永无止境的外部刺激来源的应用程序或情境。一些例子包括电子邮件、Facebook、YouTube，以及更广泛地说，整个互联网。</p><p>每当你进入一个开放系统，你就有可能变得过度刺激。例如，如果你早上做的第一件事是查看 Facebook，你可能会发现自己：</p><ul><li>无缘无故地向下滚动新闻推送，</li><li>一个接一个地看视频，或</li><li>给一个朋友发消息并开始一段漫长的对话。</li></ul><p>一旦你终于关闭 Facebook，你可能会发现自己如此受刺激，以至于很难开始工作。</p><p>这就是为什么你必须防范进入开放系统——并理解你这样做所承担的风险。在开放系统中，没有终点可以到达，没有真正完成的时刻，却有几乎无限种让你分心的方式。结果，你最终可能每天浪费数小时的时间。简而言之，开放系统创造干扰。相反，你应该努力设计封闭系统。</p><p>什么是封闭系统？</p><p>这些系统几乎或根本没有分心的空间。结果，它们迫使你处理你的任务——而且只能处理它。一些例子包括 Excel 电子表格、Word 文档或 PowerPoint 演示文稿。</p><p>这些天来，我努力在任何其他计算机操作之前先打开我正在写的书的文件。我还避免查看手机。换句话说，我用一个封闭系统开始我的一天，我也鼓励你这样做。</p><p>当你用一个封闭系统开始你的工作日时，你可以避免变得过度刺激，这将使你更容易处理具有挑战性的任务。而当你每天这样做时，你会感觉更好，并且会想要处理更多的任务。所以，也许克服拖延症并变得更有生产力的最大秘诀之一就是用封闭系统开始你的一天。这样，你可以避免无数的干扰。</p><p>记住，你早上第一件事做什么比你想象的更重要。仅仅一个小小的决定就能对你一天的生产力产生巨大影响。</p><hr><h3 id="行动步骤-2" tabindex="-1">行动步骤 <a class="header-anchor" href="#行动步骤-2" aria-label="Permalink to &quot;行动步骤&quot;">​</a></h3><p>使用你的行动指南，写下几个导致你分心的开放系统的例子。然后，写下一个你可以实施的封闭系统，以帮助你提高生产力。</p>',66)])])}const m=e(i,[["render",r]]);export{c as __pageData,m as default};
